import {
  buildStardormCatalogResponse,
  catalogResponseSchema,
  type CatalogResponse,
} from "@railbeam/stardorm-api-contract";
import { isBeamConfiguredChainId } from "./beam-chain-config";
import { fetchTyped } from "./api";
import { getStardormApiBase } from "./stardorm-axios";
import { getStardormSubgraphUrlForChain } from "./stardorm-subgraph-config";
import { fetchSubgraphBackedCatalogResponse } from "./stardorm-subgraph-catalog";

/**
 * Public marketplace catalog (no JWT).
 * Prefers the Stardorm subgraph when the active chain’s `VITE_STARDORM_SUBGRAPH_URL_*` is set; otherwise `GET /agents/catalog`;
 * if the API base URL is unset, falls back to a minimal offline catalog (Beam only).
 */
export async function fetchStardormCatalog(
  beamChainId?: number,
  viewerAddress?: `0x${string}`,
): Promise<CatalogResponse> {
  const subgraphUrl =
    beamChainId != null && isBeamConfiguredChainId(beamChainId)
      ? getStardormSubgraphUrlForChain(beamChainId)
      : undefined;
  if (subgraphUrl) {
    return fetchSubgraphBackedCatalogResponse({ subgraphUrl, viewerAddress });
  }
  const base = getStardormApiBase();
  if (!base) {
    return buildStardormCatalogResponse();
  }
  const catalogUrl = `${base.replace(/\/$/, "")}/agents/catalog`;
  return fetchTyped(catalogUrl, catalogResponseSchema);
}
